import hero from "../assets/hero.png";

function Hero() {
  return (
    <div style={styles.container}>

      <div style={styles.left}>
        <h1>AI Powered Talent Management</h1>
        <p>Smart hiring with AI technology</p>

        <button style={styles.btn}>Get Started</button>
      </div>

      <div>
        <img src={hero} alt="hero" style={styles.image} />
      </div>

    </div>
  );
}

const styles = {
  container: {
    display: "flex",
    justifyContent: "space-between",
    padding: "50px",
    alignItems: "center"
  },
  left: {
    maxWidth: "400px"
  },
  image: {
    width: "400px",
    animation: "float 3s ease-in-out infinite"
  },
  btn: {
    padding: "10px 20px",
    background: "#7C3AED",
    color: "white",
    border: "none",
    borderRadius: "5px"
  }
};

export default Hero;
